    if (is_null($this->user) && !$this->check()) {
        return;
    }

    if ($this->isImpersonator()) {
        $this->user = $this->getImpersonator();
        $this->stopImpersonate();
        return;
    }

    if ($this->user) {
        $this->user->setRememberToken(null);
        $this->user->forceSave();
    }

    $this->user = null;

    Session::flush();
    Cookie::queue(Cookie::forget($this->sessionKey));
}

